const { app } = require('@azure/functions');
const { CosmosClient } = require('@azure/cosmos');

// Configuration
const cosmosEndpoint = process.env.COSMOS_DB_ENDPOINT;
const cosmosKey = process.env.COSMOS_DB_KEY;
const databaseId = process.env.COSMOS_DB_DATABASE || 'BatchProcessingDB';
const sourceContainerId = process.env.COSMOS_DB_SOURCE_CONTAINER || 'SourceData';
const resultContainerId = process.env.COSMOS_DB_RESULT_CONTAINER || 'ProcessedData';
const checkpointContainerId = process.env.COSMOS_DB_CHECKPOINT_CONTAINER || 'Checkpoints';

const BATCH_SIZE = parseInt(process.env.BATCH_SIZE) || 500;
const MAX_CONCURRENT_OPERATIONS = parseInt(process.env.MAX_CONCURRENT) || 10;
const PROCESSING_TIMEOUT_MS = 9.5 * 60 * 1000; // 9.5 minutes - leave buffer before 10 min limit

class BatchProcessor {
    constructor(context) {
        this.context = context;
        this.client = new CosmosClient({ endpoint: cosmosEndpoint, key: cosmosKey });
        this.database = this.client.database(databaseId);
        this.sourceContainer = this.database.container(sourceContainerId);
        this.resultContainer = this.database.container(resultContainerId);
        this.checkpointContainer = this.database.container(checkpointContainerId);
        this.processedCount = 0;
        this.errorCount = 0;
        this.startTime = Date.now();
        this.isTimedOut = false;
    }

    get elapsedMs() {
        return Date.now() - this.startTime;
    }

    get remainingMs() {
        return PROCESSING_TIMEOUT_MS - this.elapsedMs;
    }

    checkTimeRemaining() {
        if (this.remainingMs <= 30000) { // 30 second buffer
            this.isTimedOut = true;
            this.context.log(`Time limit approaching. Elapsed: ${this.elapsedMs}ms. Saving checkpoint.`);
            return false;
        }
        return true;
    }

    async getCheckpoint(jobId) {
        try {
            const { resource } = await this.checkpointContainer.item(jobId, jobId).read();
            return resource;
        } catch (error) {
            if (error.code === 404) {
                return null;
            }
            throw error;
        }
    }

    async saveCheckpoint(jobId, continuationToken, processedCount, errorCount, status = 'in_progress') {
        const checkpoint = {
            id: jobId,
            partitionKey: jobId,
            continuationToken,
            processedCount,
            errorCount,
            status,
            lastUpdated: new Date().toISOString(),
            elapsedMs: this.elapsedMs
        };

        await this.checkpointContainer.items.upsert(checkpoint);
        this.context.log(`Checkpoint saved: ${JSON.stringify({ jobId, processedCount, errorCount, status })}`);
        return checkpoint;
    }

    async processItem(item) {
        // Simulate complex data transformation/processing
        try {
            const processedItem = {
                id: `processed_${item.id}`,
                partitionKey: item.partitionKey || item.id,
                originalId: item.id,
                processedAt: new Date().toISOString(),
                data: this.transformData(item),
                metadata: {
                    processingVersion: '1.0',
                    source: sourceContainerId
                }
            };

            return processedItem;
        } catch (error) {
            this.context.log(`Error processing item ${item.id}: ${error.message}`);
            throw error;
        }
    }

    transformData(item) {
        // Apply business logic transformations
        const transformed = { ...item };

        // Remove system properties
        delete transformed._rid;
        delete transformed._self;
        delete transformed._etag;
        delete transformed._attachments;
        delete transformed._ts;

        // Apply transformations
        if (transformed.values && Array.isArray(transformed.values)) {
            transformed.aggregatedSum = transformed.values.reduce((a, b) => a + b, 0);
            transformed.aggregatedAvg = transformed.aggregatedSum / transformed.values.length;
            transformed.aggregatedMin = Math.min(...transformed.values);
            transformed.aggregatedMax = Math.max(...transformed.values);
        }

        if (transformed.text && typeof transformed.text === 'string') {
            transformed.textLength = transformed.text.length;
            transformed.wordCount = transformed.text.split(/\s+/).filter(Boolean).length;
            transformed.normalizedText = transformed.text.toLowerCase().trim();
        }

        if (transformed.timestamp) {
            const date = new Date(transformed.timestamp);
            transformed.processedDate = date.toISOString().split('T')[0];
            transformed.dayOfWeek = date.getDay();
            transformed.hour = date.getHours();
        }

        transformed.isProcessed = true;
        transformed.processedTimestamp = Date.now();

        return transformed;
    }

    async writeBatchToCosmosDB(items) {
        const results = { succeeded: 0, failed: 0, errors: [] };

        // Process in concurrent chunks
        const chunks = [];
        for (let i = 0; i < items.length; i += MAX_CONCURRENT_OPERATIONS) {
            chunks.push(items.slice(i, i + MAX_CONCURRENT_OPERATIONS));
        }

        for (const chunk of chunks) {
            if (!this.checkTimeRemaining()) break;

            const operations = chunk.map(async (item) => {
                try {
                    await this.resultContainer.items.upsert(item);
                    results.succeeded++;
                } catch (error) {
                    if (error.code === 429) {
                        // Handle throttling with retry
                        const retryAfterMs = error.retryAfterInMs || 1000;
                        this.context.log(`Throttled. Retrying after ${retryAfterMs}ms`);
                        await this.delay(retryAfterMs);
                        try {
                            await this.resultContainer.items.upsert(item);
                            results.succeeded++;
                        } catch (retryError) {
                            results.failed++;
                            results.errors.push({ itemId: item.id, error: retryError.message });
                        }
                    } else {
                        results.failed++;
                        results.errors.push({ itemId: item.id, error: error.message });
                    }
                }
            });

            await Promise.all(operations);
        }

        return results;
    }

    async readBatch(query, continuationToken) {
        const queryOptions = {
            maxItemCount: BATCH_SIZE,
            continuationToken: continuationToken || undefined,
            bufferItems: true,
            maxDegreeOfParallelism: MAX_CONCURRENT_OPERATIONS
        };

        const queryIterator = this.sourceContainer.items.query(query, queryOptions);
        const { resources: items, continuationToken: nextToken, requestCharge } =
            await queryIterator.fetchNext();

        this.context.log(`Read batch: ${items ? items.length : 0} items, RU cost: ${requestCharge}`);

        return {
            items: items || [],
            continuationToken: nextToken,
            requestCharge
        };
    }

    delay(ms) {
        return new Promise(resolve => setTimeout(resolve, ms));
    }

    async run(jobId, query) {
        this.context.log(`Starting batch processing job: ${jobId}`);
        this.context.log(`Timeout configured: ${PROCESSING_TIMEOUT_MS}ms`);

        // Check for existing checkpoint to resume
        let checkpoint = await this.getCheckpoint(jobId);
        let continuationToken = null;

        if (checkpoint && checkpoint.status === 'in_progress') {
            this.context.log(`Resuming from checkpoint. Previously processed: ${checkpoint.processedCount}`);
            continuationToken = checkpoint.continuationToken;
            this.processedCount = checkpoint.processedCount;
            this.errorCount = checkpoint.errorCount;
        } else if (checkpoint && checkpoint.status === 'completed') {
            this.context.log(`Job ${jobId} already completed. Processed: ${checkpoint.processedCount}`);
            return {
                status: 'already_completed',
                processedCount: checkpoint.processedCount,
                errorCount: checkpoint.errorCount
            };
        }

        const defaultQuery = query || 'SELECT * FROM c WHERE NOT IS_DEFINED(c.isProcessed) OR c.isProcessed = false';
        let hasMoreData = true;
        let batchNumber = 0;
        let totalRUs = 0;

        try {
            while (hasMoreData && this.checkTimeRemaining()) {
                batchNumber++;
                this.context.log(`Processing batch #${batchNumber}, elapsed: ${this.elapsedMs}ms, remaining: ${this.remainingMs}ms`);

                // Read batch from source
                const { items, continuationToken: nextToken, requestCharge } =
                    await this.readBatch(defaultQuery, continuationToken);

                totalRUs += requestCharge;

                if (items.length === 0) {
                    hasMoreData = false;
                    break;
                }

                // Process items in parallel
                const processedItems = [];
                const processingChunks = [];
                for (let i = 0; i < items.length; i += MAX_CONCURRENT_OPERATIONS) {
                    processingChunks.push(items.slice(i, i + MAX_CONCURRENT_OPERATIONS));
                }

                for (const chunk of processingChunks) {
                    if (!this.checkTimeRemaining()) break;

                    const chunkResults = await Promise.allSettled(
                        chunk.map(item => this.processItem(item))
                    );

                    for (const result of chunkResults) {
                        if (result.status === 'fulfilled') {
                            processedItems.push(result.value);
                        } else {
                            this.errorCount++;
                            this.context.log(`Processing error: ${result.reason}`);
                        }
                    }
                }

                if (this.isTimedOut) break;

                // Write processed items to destination
                if (processedItems.length > 0) {
                    const writeResults = await this.writeBatchToCosmosDB(processedItems);
                    this.processedCount += writeResults.succeeded;
                    this.errorCount += writeResults.failed;

                    if (writeResults.errors.length > 0) {
                        this.context.log(`Write errors in batch #${batchNumber}: ${JSON.stringify(writeResults.errors.slice(0, 5))}`);
                    }
                }

                continuationToken = nextToken;
                hasMoreData = !!nextToken;

                // Save checkpoint after each batch
                await this.saveCheckpoint(
                    jobId,
                    continuationToken,
                    this.processedCount,
                    this.errorCount,
                    hasMoreData ? 'in_progress' : 'completed'
                );

                this.context.log(`Batch #${batchNumber} complete. Total processed: ${this.processedCount}, errors: ${this.errorCount}`);

                // Small delay to avoid overwhelming Cosmos DB
                if (hasMoreData) {
                    await this.delay(100);
                }
            }

            // Determine final status
            const finalStatus = this.isTimedOut
                ? 'paused_timeout'
                : (hasMoreData ? 'paused_has_more' : 'completed');

            // Save final checkpoint
            await this.saveCheckpoint(
                jobId,
                continuationToken,
                this.processedCount,
                this.errorCount,
                finalStatus
            );

            const result = {
                jobId,
                status: finalStatus,
                processedCount: this.processedCount,
                errorCount: this.errorCount,
                batchesProcessed: batchNumber,
                totalRUs,
                elapsedMs: this.elapsedMs,
                hasMoreData: hasMoreData || this.isTimedOut,
                continuationToken: continuationToken ? '[present]' : null
            };

            this.context.log(`Job summary: ${JSON.stringify(result)}`);
            return result;

        } catch (error) {
            this.context.log(`Fatal error in batch processing: ${error.message}`);
            this.context.log(error.stack);

            // Save error checkpoint so we can resume
            await this.saveCheckpoint(
                jobId,
                continuationToken,
                this.processedCount,
                this.errorCount,
                'error'
            ).catch(cpError => {
                this.context.log(`Failed to save error checkpoint: ${cpError.message}`);
            });

            throw error;
        }
    }
}

// Timer-triggered function for scheduled batch processing
app.timer('batchProcessorTimer', {
    schedule: '0 */30 * * * *', // Every 30 minutes
    runOnStartup: false,
    handler: async (myTimer, context) => {
        context.log('Timer-triggered batch processing started');

        const jobId = `batch_${new Date().toISOString().split('T')[0]}_scheduled`;
        const processor = new BatchProcessor(context);

        try {
            const result = await processor.run(jobId);

            if (result.status === 'paused_timeout' || result.status === 'paused_has_more') {
                context.log(`Job paused - will resume on next timer trigger. Processed so far: ${result.processedCount}`);
            }

            return result;
        } catch (error) {
            context.log(`Batch processing failed: ${error.message}`);
            throw error;
        }
    }
});

// HTTP-triggered function for on-demand batch processing
app.http('batchProcessorHttp', {
    methods: ['POST'],
    authLevel: 'function',
    handler: async (request, context) => {
        context.log('HTTP-triggered batch processing started');

        let body;
        try {
            body = await request.json();
        } catch {
            body = {};
        }

        const jobId = body.jobId || `batch_${Date.now()}_manual`;
        const query = body.query || null;

        const processor = new BatchProcessor(context);

        try {
            const result = await processor.run(jobId, query);

            return {
                status: result.status === 'completed' ? 200 : 202,
                jsonBody: {
                    success: true,
                    ...result
                },
                headers: {
                    'Content-Type': 'application/json'
                }
            };
        } catch (error) {
            context.log(`Batch processing failed: ${error.message}`);

            return {
                status: 500,
                jsonBody: {
                    success: false,
                    error: error.message,
                    jobId,
                    processedCount: processor.processedCount,
                    errorCount: processor.errorCount
                },
                headers: {
                    'Content-Type': 'application/json'
                }
            };
        }
    }
});

// HTTP endpoint to check job status
app.http('batchJobStatus', {
    methods: ['GET'],
    authLevel: 'function',
    route: 'batch/status/{jobId}',
    handler: async (request, context) => {
        const jobId = request.params.jobId;
        context.log(`Checking status for job: ${jobId}`);

        const client = new CosmosClient({ endpoint: cosmosEndpoint, key: cosmosKey });
        const container = client.database(databaseId).container(checkpointContainerId);

        try {
            const { resource: checkpoint } = await container.item(jobId, jobId).read();

            if (!checkpoint) {
                return {
                    status: 404,
                    jsonBody: { error: 'Job not found', jobId }
                };
            }

            return {
                status: 200,
                jsonBody: {
                    jobId: checkpoint.id,
                    status: checkpoint.status,
                    processedCount: checkpoint.processedCount,
                    errorCount: checkpoint.errorCount,
                    lastUpdated: checkpoint.lastUpdated,
                    elapsedMs: checkpoint.elapsedMs,
                    hasContinuation: !!checkpoint.continuationToken
                },
                headers: {
                    'Content-Type': 'application/json'
                }
            };
        } catch (error) {
            if (error.code === 404) {
                return {
                    status: 404,
                    jsonBody: { error: 'Job not found', jobId }
                };
            }

            return {
                status: 500,
                jsonBody: { error: error.message }
            };
        }
    }
});

// Queue-triggered function for chained/continuation processing
app.storageQueue('batchProcessorQueue', {
    queueName: 'batch-processing-queue',
    connection: 'AzureWebJobsStorage',
    handler: async (queueItem, context) => {
        context.log('Queue-triggered batch processing started');

        const { jobId, query } = typeof queueItem === 'string'
            ? JSON.parse(queueItem)
            : queueItem;

        const processor = new BatchProcessor(context);

        try {
            const result = await processor.run(jobId, query);

            // If there's more data to process, re-queue for continuation
            if (result.status === 'paused_timeout' || result.status === 'paused_has_more') {
                context.log(`Re-queuing job ${jobId} for continuation processing`);
                // Note: In production, use @azure/storage-queue SDK to re-enqueue
                // or use Durable Functions for orchestration
            }

            return result;
        } catch (error) {
            context.log(`Queue batch processing failed: ${error.message}`);
            throw error;
        }
    }
});

